def to_lowercase(input):  # Define a new Python Function named "to_lowercase" which accepts input parameter 'input'. The function returns the lowercased version of string that is passed as argument into it, using builtin python's str and list comprehension.  
    return ' '.join([i for i in input.split()])  # Split word by space (as a rule), then loop over words with join to form final sentence back up via joining spaces between each of the individual parts into one long string that is returned as output from function, this will make sure there are no extra leading or trailing whitespaces in our result.